const STROKE_COLOR = "#F0D4D3";

// ─── Figma coordinate constants ──────────────────────────────────────────────
// The original Figma SVG uses viewBox 0 0 1612 300:
//   - Top scallop wave lives in y: 0 → 119   (clipped to y: 0 → 56)
//   - Middle rect fills y: 56 → 244
//   - Bottom scallop wave lives in y: 181 → 300 (clipped to y: 244 → 300)
// The clip-paths crop each wave to only show ~56px of the outer scallop edge.

const SVG_W = 1612;
const CLIP_H = 56; // visible height of each scallop edge after clipping

interface ScallopBorderProps {
  children: React.ReactNode;
  /** Unique ID prefix to avoid SVG clipPath collisions when multiple instances exist on the same page */
  id?: string;
}

const ScallopBorder: React.FC<ScallopBorderProps> = ({
  children,
  id = "scallop",
}) => {
  const clipTopId = `${id}-clip-top`;
  const clipBottomId = `${id}-clip-bottom`;

  return (
    <div className="relative w-full">
      {/* ── Top scallop wave ── */}
      <svg
        viewBox={`0 0 ${SVG_W} ${CLIP_H}`}
        preserveAspectRatio="none"
        xmlns="http://www.w3.org/2000/svg"
        aria-hidden="true"
        className="w-full block"
        style={{ height: 28 }}
      >
        <defs>
          <clipPath id={clipTopId}>
            <rect width={SVG_W} height={CLIP_H} x="0" y="0" />
          </clipPath>
        </defs>
        <g clipPath={`url(#${clipTopId})`}>
          <path
            d={TOP_SCALLOP_PATH}
            fill="white"
            stroke={STROKE_COLOR}
            strokeWidth="2"
          />
        </g>
      </svg>

      {/* ── Content area with pink side borders ── */}
      <div
        className="relative bg-white"
        style={{
          borderLeft: `1.5px solid ${STROKE_COLOR}`,
          borderRight: `1.5px solid ${STROKE_COLOR}`,
        }}
      >
        {children}
      </div>

      {/* ── Bottom scallop wave ── */}
      {/*
       * The bottom wave is the same shape as the top, flipped vertically.
       * We reuse TOP_SCALLOP_PATH and flip the entire SVG with scale(1,-1)
       * via CSS transform. This guarantees both edges render identically.
       */}
      <svg
        viewBox={`0 0 ${SVG_W} ${CLIP_H}`}
        preserveAspectRatio="none"
        xmlns="http://www.w3.org/2000/svg"
        aria-hidden="true"
        className="w-full block"
        style={{ height: 28, transform: "scaleY(-1)" }}
      >
        <defs>
          <clipPath id={clipBottomId}>
            <rect width={SVG_W} height={CLIP_H} x="0" y="0" />
          </clipPath>
        </defs>
        <g clipPath={`url(#${clipBottomId})`}>
          <path
            d={TOP_SCALLOP_PATH}
            fill="white"
            stroke={STROKE_COLOR}
            strokeWidth="2"
          />
        </g>
      </svg>
    </div>
  );
};

export default ScallopBorder;